import { PublicActionPage } from '@domain/publicActionPage';
import { DonorProfileResponse } from '@state/user/donor_profile';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { BusinessIcon } from '../../../icons';
import { Meta } from '../../../Meta';
import { SignedInSection } from '../SignedInSection';

type Props = {
  actionPage: PublicActionPage;
  donorProfile: DonorProfileResponse;
};

export const EmploymentSection = ({ actionPage, donorProfile }: Props) => {
  const { t } = useTranslation('donors');
  const { t: tCustomFields } = useTranslation('customFields');
  const { setValue, trigger } = useFormContext();

  const {
    employer,
    employerCity,
    employerCountry,
    employerLine1,
    employerPostalCode,
    employerRegion,
    occupation,
  } = donorProfile;

  const nonEmployedOccupationOptions = useMemo<string[]>(
    () => t('donorForms.contactInformation.occupationOptions', { returnObjects: true }),
    [t]
  );

  const isCurrentlyEmployed = useMemo(
    () => !nonEmployedOccupationOptions?.find((opt) => opt === occupation),
    [occupation, nonEmployedOccupationOptions]
  );

  const isSavedOccupationValid = useMemo(
    () =>
      occupation &&
      (!isCurrentlyEmployed ||
        !actionPage.fieldConfiguration?.occupationOptions?.length ||
        actionPage.fieldConfiguration.occupationOptions.includes(occupation)),
    [occupation, isCurrentlyEmployed, actionPage.fieldConfiguration?.occupationOptions]
  );

  useEffect(() => {
    if (actionPage.fieldConfiguration?.displayEmployment) {
      if (employer) {
        setValue('employerName', employer);
        trigger('employerName');
      }

      if (occupation) {
        setValue('employed', isCurrentlyEmployed);
        trigger('employed');

        if (isSavedOccupationValid) {
          setValue('occupation', occupation);
          trigger('occupation');
        }
      }
    }

    if (actionPage.fieldConfiguration.includeEmployerAddress) {
      if (actionPage.fieldConfiguration.employerAddressType === 'zip') {
        setValue('employerAddressAttributes.postalCode', employerPostalCode);
        trigger('employerAddressAttributes.postalCode');
      } else {
        setValue('employerAddressAttributes.city', employerCity);
        setValue('employerAddressAttributes.country', employerCountry);
        setValue('employerAddressAttributes.line1', employerLine1);
        setValue('employerAddressAttributes.postalCode', employerPostalCode);
        setValue('employerAddressAttributes.region', employerRegion);
        trigger('employerAddressAttributes.city');
        trigger('employerAddressAttributes.country');
        trigger('employerAddressAttributes.line1');
        trigger('employerAddressAttributes.postalCode');
        trigger('employerAddressAttributes.region');
      }
    }

    // run once on mount
  }, []);

  if (!actionPage.fieldConfiguration?.displayEmployment || (!employer && !isSavedOccupationValid)) {
    return null;
  }

  return (
    <SignedInSection icon={<BusinessIcon />}>
      <div className="flex grow flex-col">
        <Meta className="text-[13px] leading-4 !text-neutral-500" variant="regular">
          {tCustomFields('employment.label')}
        </Meta>
        {isCurrentlyEmployed && employer ? (
          <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
            {employer}
          </Meta>
        ) : null}
        {isSavedOccupationValid ? (
          <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
            {occupation}
          </Meta>
        ) : null}
        {isCurrentlyEmployed && actionPage.fieldConfiguration.includeEmployerAddress ? (
          <>
            {employerLine1 ? (
              <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
                {employerLine1}
              </Meta>
            ) : null}
            {employerCity && employerRegion ? (
              <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
                {employerCity}, {employerRegion} {employerPostalCode}
              </Meta>
            ) : null}
            {employerCountry ? (
              <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
                {employerCountry}
              </Meta>
            ) : null}
          </>
        ) : null}
      </div>
    </SignedInSection>
  );
};

